+    fn owned_itemset_materializes_integer_sidecar_for_large_exact_values() {
+        let mut arr = UFuncArray::from_storage(vec![2], ArrayStorage::I64(vec![1, 2])).unwrap();
+        assert!(!arr.has_integer_sidecar());
